import React, { useState, useEffect, useMemo } from 'react';
import Select from 'react-select';
import './AddPurchase.css';

const AddPurchase = ({ handleAdd, locations, vendors }) => {
  const initialPurchaseState = {
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    price: '',
    vendor: '',
    vendorname: '',
  };

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);
  const [errorMessage, setErrorMessage] = useState('');
  
  useEffect(() => {
    // ... (existing code)
  }, [newPurchase.materialid, vendors]);
  
  // ... (existing code)

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Check if all the required fields are filled
    if (!newPurchase.location || !newPurchase.materialid || !newPurchase.quantity || !newPurchase.price || !newPurchase.vendorname) {
      setErrorMessage('Please fill out all the required fields.');
      return;
    }

    // Clear the error message if there are no missing fields
    setErrorMessage('');

    // Convert the selected vendor name back to vendor ID before submitting to the API
    const selectedVendor = vendors.find((vendor) => vendor.name === newPurchase.vendorname);
    const updatedPurchase = {
      ...newPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '',
    };

    try {
      // Check if the material ID exists in material_changes
      const responseChanges = await fetch(`http://localhost:8081/materialchangesAPI/${newPurchase.materialid}`);
      const dataChanges = await responseChanges.json();
      console.log('Data changes fetched:', dataChanges);

      // If material ID exists in material_changes and price or vendor has changed, create a new record
      if (dataChanges && (
        dataChanges.price !== updatedPurchase.price || dataChanges.vendor !== updatedPurchase.vendor
      )) {
        const response = await fetch('http://localhost:8081/materialchangesAPI/', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            material_id: newPurchase.materialid,
            price: updatedPurchase.price,
            vendor: updatedPurchase.vendor,
          }),
        });

        if (!response.ok) {
          // Handle the case when the response status is not in the 200-299 range (e.g., 404, 500, etc.)
          console.error('Failed to create material change:', response);
          // You can add additional error handling here, such as showing a user-friendly message.
          return;
        }
      } else {
        // If material ID does not exist in material_changes, create a new record
        const response = await fetch('http://localhost:8081/materialchangesAPI/', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            material_id: newPurchase.materialid,
            price: updatedPurchase.price,
            vendor: updatedPurchase.vendor,
          }),
        });

        if (!response.ok) {
          // Handle the case when the response status is not in the 200-299 range (e.g., 404, 500, etc.)
          console.error('Failed to create material change:', response);
          // You can add additional error handling here, such as showing a user-friendly message.
          return;
        }
      }
    } catch (error) {
      console.error('Error handling the form submission:', error);
      // You can add additional error handling here, such as showing a user-friendly message.
      return;
    }

    // Call the handleAdd function to update the state with the new purchase data
    handleAdd(updatedPurchase);

    // Reset the form state after submitting
    setNewPurchase(initialPurchaseState);
  };

  const handleVendorChange = (selectedOption) => {
    // ... (existing code)
  };

  const handleMaterialIdChange = (e) => {
    // Reset the material name when the material ID changes
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      materialid: e.target.value,
      materialname: '',
    }));
  };

  const handleAddNewMaterial = () => {
    const addMaterialUrl = '/AddMaterial'; // Replace this with the actual URL of the AddMaterial component
    const confirmAddNewMaterial = window.confirm('Material ID does not exist. Do you want to add a new material?');

    if (confirmAddNewMaterial) {
      // Redirect the user to the AddMaterial component
      window.location.href = addMaterialUrl;
    }
  };

  const vendorOptions = useMemo(
    () => vendors.map((vendor) => ({ value: vendor.name, label: vendor.name })),
    [vendors]
  );

  return (
    <form onSubmit={handleSubmit} className='add-purchase-form'>
      {errorMessage && <p className="error-message">{errorMessage}</p>}
      <div>
        <label>Location:</label>
        <select name="location" value={newPurchase.location} onChange={handleChange}>
          {/* ... (existing code) */}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={newPurchase.materialid} onChange={handleMaterialIdChange} />
        {/* Add a button to handle adding a new material */}
        <button type="button" onClick={handleAddNewMaterial}>Add New Material</button>
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="materialname" value={newPurchase.materialname} readOnly />
      </div>
      {/* Rest of the form fields */}
      <button type="submit" className="add_purchase_btn">Add Purchase</button>
    </form>
  );
};

export default AddPurchase;
